// // This module implements a 4-input NOR gate with inverted inputs C_N and D_N.
module top_module(
    Y  ,
    A  ,
    B  ,
    C_N,
    D_N
);output Y  ;
    input  A  ;
    input  B  ;
    input  C_N;
    input  D_N;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;

    assign Y = ~(A | B | C_N | D_N);

endmodule
